## 4.3 Run Assignment Optimizer

### 4.3.1 Purpose

Optimize daily train-to-route assignments for mileage balancing while respecting hard constraints (fitness, PM due, **unavailability**, **service demand**) and minimizing soft constraint penalties.

### 4.3.2 Optimizer Service (TypeScript Wrapper)

```typescript
interface OptimizerConfig {
  binaryPath: string;          // ./mms-optimizer
  maxSolveTimeSeconds: number; // 30
  numWorkers: number;          // 4
  timeoutMs: number;           // 60000
  fallbackEnabled: boolean;    // true
}

class RunAssignmentOptimizer {
  private process: Subprocess | null = null;

  async optimize(input: OptimizerInput): Promise<OptimizerResult> {
    const startTime = Date.now();

    try {
      // Try C++ optimizer first
      const result = await this.runCppOptimizer(input);

      // Validate result
      if (result.status === 'INFEASIBLE' && this.config.fallbackEnabled) {
        this.logger.warn('C++ optimizer returned INFEASIBLE, using fallback');
        return await this.runFallbackOptimizer(input);
      }

      return result;

    } catch (error) {
      this.logger.error({ error }, 'C++ optimizer failed, using fallback');

      if (this.config.fallbackEnabled) {
        return await this.runFallbackOptimizer(input);
      }

      throw error;
    }
  }

  private async runCppOptimizer(input: OptimizerInput): Promise<OptimizerResult> {
    return new Promise((resolve, reject) => {
      const timeout = setTimeout(() => {
        this.process?.kill();
        reject(new Error('Optimizer timeout'));
      }, this.config.timeoutMs);

      this.process = Bun.spawn([this.config.binaryPath], {
        stdin: 'pipe',
        stdout: 'pipe',
        stderr: 'pipe'
      });

      // Write input
      const writer = this.process.stdin.getWriter();
      writer.write(new TextEncoder().encode(JSON.stringify(input) + '\n'));
      writer.close();

      // Read stdout (results)
      const results: any[] = [];
      const reader = this.process.stdout.getReader();
      const decoder = new TextDecoder();
      let buffer = '';

      const readStream = async () => {
        while (true) {
          const { done, value } = await reader.read();
          if (done) break;

          buffer += decoder.decode(value, { stream: true });
          const lines = buffer.split('\n');
          buffer = lines.pop() || '';

          for (const line of lines) {
            if (!line.trim()) continue;

            try {
              const msg = JSON.parse(line);

              if (msg.type === 'PROGRESS') {
                this.emitProgress(msg);
              } else if (msg.type === 'RESULT') {
                clearTimeout(timeout);
                resolve(this.mapResult(msg));
                return;
              }
            } catch (e) {
              this.logger.warn({ line }, 'Failed to parse optimizer output');
            }
          }
        }
      };

      // Read stderr (metrics/logs)
      this.readStderr(this.process.stderr);

      readStream().catch(reject);

      this.process.exited.then((code) => {
        clearTimeout(timeout);
        if (code !== 0 && results.length === 0) {
          reject(new Error(`Optimizer exited with code ${code}`));
        }
      });
    });
  }

  private async runFallbackOptimizer(input: OptimizerInput): Promise<OptimizerResult> {
    // TypeScript greedy fallback
    const assignments: Assignment[] = [];
    const unassigned: UnassignedTrain[] = [];
    const assignedTrainIds = new Set<string>();

    // Sort routes by priority (required trains desc)
    const sortedRoutes = [...input.routes].sort(
      (a, b) => b.required_trains - a.required_trains
    );

    // Sort trains by fitness and mileage balance
    const sortedTrains = [...input.trains]
      .filter(t => t.fitness_status === 'FIT')
      .sort((a, b) => {
        // Prioritize under-utilized trains
        const aBalance = a.current_mileage - a.target_mileage;
        const bBalance = b.current_mileage - b.target_mileage;
        return aBalance - bBalance;
      });

    for (const route of sortedRoutes) {
      let assigned = 0;

      for (const train of sortedTrains) {
        if (assigned >= route.required_trains) break;
        if (assignedTrainIds.has(train.id)) continue;

        // Check hard constraints
        const hardViolation = this.checkHardConstraints(train, route, input);
        if (hardViolation) {
          continue;
        }

        // Check fleet compatibility
        if (route.allowed_fleets.length > 0 && 
            !route.allowed_fleets.includes(train.fleet_id)) {
          continue;
        }

        // Assign
        assignments.push({
          train_id: train.id,
          route_id: route.id,
          score: this.calculateScore(train, route),
          explanation: [
            {
              constraint_type: 'SOFT',
              constraint_name: 'MILEAGE_BALANCE',
              impact: train.current_mileage - train.target_mileage,
              description: `Train is ${Math.abs(train.current_mileage - train.target_mileage)}km ${
                train.current_mileage < train.target_mileage ? 'under' : 'over'
              } target`
            }
          ]
        });

        assignedTrainIds.add(train.id);
        assigned++;
      }

      // Record shortfall
      if (assigned < route.required_trains) {
        unassigned.push({
          route_id: route.id,
          shortfall: route.required_trains - assigned,
          reason: 'Insufficient fit trains available'
        });
      }
    }

    // Record unassigned trains with reasons
    for (const train of input.trains) {
      if (assignedTrainIds.has(train.id)) continue;

      const reason = train.fitness_status !== 'FIT' 
        ? `Train is ${train.fitness_status}`
        : this.findBlockingConstraint(train, input);

      unassigned.push({
        train_id: train.id,
        reason,
        blocking_constraints: this.getBlockingConstraints(train, input)
      });
    }

    return {
      type: 'RESULT',
      request_id: input.request_id,
      status: 'FALLBACK',
      solve_time_ms: 0,
      assignments,
      unassigned,
      material_warnings: [],
      summary: {
        total_penalty: 1e6,  // High penalty for fallback
        trains_assigned: assignments.length,
        trains_unassigned: unassigned.length,
        soft_constraint_breakdown: {},
        material_blocks: 0
      }
    };
  }

  private checkHardConstraints(
    train: Train,
    route: Route,
    input: OptimizerInput
  ): string | null {
    // NEW v2.1: Check unavailability events first
    if (input.unavailability_events) {
      for (const event of input.unavailability_events) {
        if (event.train_id === train.id && 
            event.status === 'ACTIVE' && 
            event.blocks_run_assignment) {
          return `Train unavailable: ${event.event_type} - ${event.description || event.external_reference || 'No details'}`;
        }
      }
    }

    // Check explicit hard constraints
    for (const constraint of input.hard_constraints) {
      if (constraint.train_id === train.id) {
        return constraint.description;
      }
    }

    // NEW v2.1: Check route compatibility
    if (input.route_compatibility) {
      const incompatible = input.route_compatibility.find(
        c => c.train_id === train.id && 
             c.route_id === route.id && 
             !c.is_compatible
      );
      if (incompatible) {
        return `Route incompatible: ${incompatible.constraint_type} - ${incompatible.restriction_reason || 'Technical restriction'}`;
      }
    }

    // Check pending PMs that block assignment
    for (const pm of input.pending_pms) {
      if (pm.train_id === train.id && 
          pm.target_date <= new Date().toISOString().split('T')[0]) {
        // Check if materials are available
        const blocked = pm.required_materials.some(mat => {
          if (mat.criticality !== 'BLOCKING') return false;

          const position = input.material_positions.find(
            p => p.part_number === mat.part_number && 
                 p.depot_id === train.home_depot_id
          );

          return !position || position.quantity_available < mat.quantity;
        });

        if (!blocked) {
          return `PM ${pm.pm_type} due today`;
        }
      }
    }

    return null;
  }
}

// NEW v2.1: Extended optimizer input interface
interface OptimizerInput {
  request_id: string;
  assignment_date: string;

  trains: {
    id: string;
    train_number: string;
    fleet_id: string;
    current_mileage: number;
    target_mileage: number;
    fitness_status: 'FIT' | 'RESTRICTED' | 'GROUNDED';
    home_depot_id: string;
  }[];

  routes: {
    id: string;
    route_code: string;
    expected_km: number;
    required_trains: number;
    allowed_fleets: string[];
  }[];

  hard_constraints: {
    train_id: string;
    type: string;
    description: string;
  }[];

  pending_pms: {
    train_id: string;
    pm_type: string;
    target_date: string;
    required_materials: {
      part_number: string;
      quantity: number;
      criticality: 'BLOCKING' | 'DEFERRABLE' | 'CONSUMABLE';
    }[];
  }[];

  material_positions: {
    depot_id: string;
    part_number: string;
    quantity_available: number;
  }[];

  // NEW v2.1: Unavailability events
  unavailability_events?: {
    train_id: string;
    event_type: string;
    status: 'ACTIVE' | 'RESOLVED';
    blocks_run_assignment: boolean;
    description?: string;
    external_reference?: string;
    estimated_return_date?: string;
  }[];

  // NEW v2.1: Route compatibility constraints
  route_compatibility?: {
    train_id: string;
    route_id: string;
    is_compatible: boolean;
    constraint_type?: string;
    restriction_reason?: string;
  }[];

  // NEW v2.1: Service demand for validation
  service_demand?: {
    min_trains_required: number;
    standby_buffer: number;
  };
